import{_ as r,C as i,o as n,c as s,j as a,a as o,E as l,a7 as d}from"./chunks/framework.C4ZIv4ii.js";const w=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1782147356000}'),c={name:"changelog.md"},h={id:"v1-5-0",tabindex:"-1"};function u(g,e,p,m,f,b){const t=i("Badge");return n(),s("div",null,[e[3]||(e[3]=a("h1",{id:"changelog",tabindex:"-1"},[o("Changelog "),a("a",{class:"header-anchor",href:"#changelog","aria-label":'Permalink to "Changelog"'},"​")],-1)),e[4]||(e[4]=a("p",null,[o("All notable changes to "),a("strong",null,"FalconCMS"),o(" are documented here."),a("br"),o(" Format follows "),a("a",{href:"https://keepachangelog.com/en/1.0.0/",target:"_blank",rel:"noreferrer"},"Keep a Changelog"),o(" — versions are sorted newest first.")],-1)),e[5]||(e[5]=a("hr",null,null,-1)),a("h2",h,[e[0]||(e[0]=o("v1.5.0 ",-1)),l(t,{type:"tip",text:"Latest"}),e[1]||(e[1]=o()),e[2]||(e[2]=a("a",{class:"header-anchor",href:"#v1-5-0","aria-label":'Permalink to "v1.5.0 <Badge type="tip" text="Latest" /> {#v1-5-0}"'},"​",-1))]),e[6]||(e[6]=d('<p><strong>Released: 2026-06-22</strong></p><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Registration — duplicate username</strong> — Usernames derived from the email local part are now sanitized and made unique (<code>john@a.com</code> and <code>john@b.com</code> no longer collide → <code>john</code>, <code>john1</code>…), fixing the duplicate-username error on sign-up</li><li><strong>Admin user create/edit</strong> — Validation errors are now displayed (a top summary plus per-field messages) instead of a database constraint crash; inputs repopulate on failure, and a success message is shown</li><li><strong>User update redirect</strong> — Saving a user now returns to the same edit page with the success notice, instead of jumping to the user list</li></ul><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Password strength &amp; match</strong> — The admin user create/edit password fields now show a live strength meter and a password-match indicator, matching the registration page</li></ul><h2 id="v1-4-9" tabindex="-1">v1.4.9 <a class="header-anchor" href="#v1-4-9" aria-label="Permalink to &quot;v1.4.9 {#v1-4-9}&quot;">​</a></h2><p><strong>Released: 2026-06-22</strong></p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Analytics — major overhaul</strong> — Bot/crawler filtering, geo location (country/city with flags), real-time active users with a 30-minute sparkline and live tables, sessions, bounce rate, new vs returning visitors, traffic channels, e-commerce conversion KPIs and a visit→cart→checkout→order funnel, plus donut charts for channels, returning visitors and top countries</li><li><strong>Analytics — data retention</strong> — New <code>falcon:prune-analytics</code> command with a daily schedule and a cron-independent fallback, with a configurable retention window</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — The default footer logo now uses the white brand logo (the dark logo was invisible on the dark footer) at a larger size, automatically darkened on light footer backgrounds; a custom uploaded logo is always shown as-is</li></ul><h2 id="v1-4-8" tabindex="-1">v1.4.8 <a class="header-anchor" href="#v1-4-8" aria-label="Permalink to &quot;v1.4.8 {#v1-4-8}&quot;">​</a></h2><p><strong>Released: 2026-06-22</strong></p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Registration — email verification</strong> — New sign-ups are no longer logged in immediately; a time-limited (5-minute) signed verification link is emailed instead, and sign-in is blocked until the address is verified. Includes a notice page and a throttled resend flow. A migration marks all existing users as verified so no one is locked out</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Order status emails</strong> — Customers are now emailed on every order status change (pending, on-hold, processing, completed, delivered, cancelled, refunded, partially-refunded, failed), not just on delivery — for both single and bulk updates</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Product Meta element</strong> — Now available only in post-card mode, like Post Meta and Content</li></ul><h2 id="v1-4-7" tabindex="-1">v1.4.7 <a class="header-anchor" href="#v1-4-7" aria-label="Permalink to &quot;v1.4.7 {#v1-4-7}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Builder — Product Meta element</strong> — A new element that displays a product&#39;s price (with sale), SKU, availability, stock quantity and type; each field toggleable, with stacked/inline layout, alignment, labels and full design controls</li><li><strong>Builder — Ticker</strong> — Configurable item spacing, a duplicate-item button, and live scrolling in the builder canvas</li><li><strong>Dynamic sources — Product group</strong> — Bind any text field to live product data (price, regular/sale price, SKU, stock status, stock quantity); dynamic fields now show a live preview right in the builder using the real value of the post being edited</li></ul><h2 id="v1-4-6" tabindex="-1">v1.4.6 <a class="header-anchor" href="#v1-4-6" aria-label="Permalink to &quot;v1.4.6 {#v1-4-6}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong><code>falcon:update</code> — stale published view overrides</strong> — Update now removes the entire published <code>resources/views/vendor/falcon-cms</code> directory, not just the <code>admin</code> subfolder. A leftover published copy of a namespaced package view (e.g. <code>frontend/builder/column.blade.php</code>) silently shadows the real vendor view, so layout fixes never appear on the site no matter how many caches are cleared. Clearing the whole override namespace guarantees the package&#39;s own views are always used</li></ul><h2 id="v1-4-5" tabindex="-1">v1.4.5 <a class="header-anchor" href="#v1-4-5" aria-label="Permalink to &quot;v1.4.5 {#v1-4-5}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard Update — stale frontend after update</strong> — The dashboard &quot;Update&quot; now resets the php-fpm OPcache from the web request itself. Previously the <code>falcon:update</code> subprocess ran under CLI php, whose <code>opcache_reset()</code> only clears the CLI OPcache — the php-fpm workers that serve frontend pages kept executing the old compiled Blade views, so builder/layout fixes did not appear on the live site until a manual container restart</li><li><strong>Dashboard footer</strong> — Default admin footer credit changed to &quot;Theme developed by Falcon CMS&quot;</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Taxonomy screens</strong> — Removed the non-functional &quot;Screen Options&quot; and &quot;Help&quot; buttons from the top-right of all taxonomy list pages (Categories, Tags, Product Categories, Product Tags, and custom ACPT taxonomy terms)</li></ul><h2 id="v1-4-4" tabindex="-1">v1.4.4 <a class="header-anchor" href="#v1-4-4" aria-label="Permalink to &quot;v1.4.4 {#v1-4-4}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard Update — php-fpm binary</strong> — The dashboard &quot;Update&quot; button ran <code>falcon:update</code> with <code>PHP_BINARY</code>, which in a web (php-fpm) request points at the php-fpm executable and cannot run <code>artisan</code> (it printed FastCGI usage and aborted, so migrations/cache-clear/OPcache reset never ran). The updater now locates a real CLI php binary, checking absolute paths first since the php-fpm worker often runs with a stripped <code>PATH</code></li></ul><h2 id="v1-4-3" tabindex="-1">v1.4.3 <a class="header-anchor" href="#v1-4-3" aria-label="Permalink to &quot;v1.4.3 {#v1-4-3}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Page Builder — Preview mode blank canvas</strong> — Toggling the builder&#39;s eye-icon Preview no longer blanks the whole canvas. In preview the canvas kept <code>grid-area: auto</code>, which auto-placed it into the now-hidden sidebar&#39;s 0-width grid column; it is now pinned to its named <code>canvas</code> area so the design stays visible</li></ul><h2 id="v1-4-2" tabindex="-1">v1.4.2 <a class="header-anchor" href="#v1-4-2" aria-label="Permalink to &quot;v1.4.2 {#v1-4-2}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Page Builder — Row content layout</strong> — Elements inside a column with Content Layout set to &quot;Row&quot; now stay side-by-side and never wrap to the next line (<code>flex-wrap: nowrap</code>); previously <code>flex-wrap: wrap</code> caused elements to stack when they did not fit</li><li><strong><code>falcon:update</code> — OPcache</strong> — OPcache is now reset after cache clearing so freshly compiled Blade views are served immediately without requiring a server restart</li></ul><hr><h2 id="v1-4-1" tabindex="-1">v1.4.1 <a class="header-anchor" href="#v1-4-1" aria-label="Permalink to &quot;v1.4.1 {#v1-4-1}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Multi-device login</strong> — <code>-1</code> value for Max Devices now correctly means unlimited; previously <code>count() &gt;= -1</code> was always true, blocking all logins even when unlimited was intended</li><li><strong>Page Builder — Nested Column row layout</strong> — Elements inside a column with Content Layout set to &quot;Row&quot; now render side-by-side on the frontend; previously <code>width: 100%</code> on element wrappers caused items to stack vertically despite <code>flex-direction: row</code></li></ul><hr><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0 {#v1-4-0}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Demo mode — Login page</strong> — Demo credentials box displayed above login form when <code>APP_DEMO=true</code></li><li><strong>Demo mode — User management</strong> — All fields on user create and user edit pages disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Demo mode — Settings</strong> — <code>register_url</code> and <code>login_url</code> inputs disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Docs — Demo page</strong> — Live demo request page with lead capture form; credentials sent to visitor&#39;s email via EmailJS after form submission</li></ul><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Default FalconCMS logo always shown in footer column 1; embedded as base64 to remove file dependency; <code>theme_footer_logo</code> / <code>theme_site_logo</code> cleared from DB on <code>falcon:update</code> so stale overrides are never applied</li><li><strong><code>falcon:update</code></strong> — Published admin views deleted on update so vendor views are always served fresh (no stale published copies)</li></ul><hr><h2 id="v1-3-18" tabindex="-1">v1.3.18 <a class="header-anchor" href="#v1-3-18" aria-label="Permalink to &quot;v1.3.18 {#v1-3-18}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Customizer — Performance</strong> — &quot;Clear All Cache&quot; button for one-click cache clearing from the admin</li></ul><h3 id="fixed-10" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-10" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Product editor</strong> — Added <code>x-cloak</code> to product data metabox to prevent Alpine.js FOUC on page load</li><li><strong><code>falcon:update</code></strong> — Admin views automatically re-published during update to keep published copies in sync</li><li><strong>Sale end date</strong> — <code>sale_ends_at</code> datetime input minimum set using client-side local time instead of server UTC</li><li><strong>Product archive</strong> — <code>productCategories</code> relation used in <code>archive-product.blade.php</code>; eager loaded on CPT archive queries to prevent N+1</li><li><strong>Sale end date validation</strong> — Removed <code>after:now</code> rule causing false rejections in some timezones</li><li><strong>PHP_BINARY</strong> — Correctly resolved to CLI <code>php</code> in web (php-fpm) context</li><li><strong>Product categories</strong> — Category label display corrected on product cards and single product pages</li><li><strong>Shop</strong> — Tab active-state bug fixed; <code>hold_stock</code> order cancellation implemented</li><li><strong>Page Builder</strong> — Fixed offset constants in <code>parseColumnsFromContent()</code></li><li><strong>Hooks &amp; helpers</strong> — Remaining <code>lazy_</code> class and helper references renamed to <code>falcon_</code></li></ul><hr><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0 {#v1-0-0}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><p>Initial public release of <strong>FalconCMS</strong> — a powerful Laravel CMS package with page builder, e-commerce, and a WordPress-like admin dashboard.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><strong>WordPress-like Admin Dashboard</strong> — Sidebar navigation, top bar, role-based permissions, activity logs</li><li><strong>Page Builder (Falcon Builder)</strong> — Drag-and-drop visual editor with rows, columns, and element blocks</li><li><strong>Post &amp; Page Management</strong> — Custom post types, categories, tags, featured images, SEO fields</li><li><strong>Media Library</strong> — Upload, manage, and select images/files across the admin</li><li><strong>User &amp; Role Management</strong> — Granular permission system with custom roles</li><li><strong>Multi-language Support</strong> — Built-in language management</li><li><strong>Theme System</strong> — Installable themes with Customizer support (header, footer, colors, typography)</li><li><strong>Hook Architecture</strong> — WordPress-style <code>add_lazy_action</code> / <code>add_lazy_filter</code> for extensibility</li><li><strong>Custom Options Pages</strong> — Register custom settings pages via config</li></ul><h3 id="e-commerce-shop" tabindex="-1">E-Commerce (Shop) <a class="header-anchor" href="#e-commerce-shop" aria-label="Permalink to &quot;E-Commerce (Shop)&quot;">​</a></h3><ul><li><strong>Product Management</strong> — Simple and variable products, SKU, stock, sale price with scheduled expiry (<code>sale_ends_at</code>)</li><li><strong>Digital / Downloadable Products</strong> — Attach files from the media library; secure token-based download links with expiry and download count limits</li><li><strong>Orders</strong> — Full order lifecycle (pending → processing → shipped → completed), order notes, status history</li><li><strong>Cart &amp; Checkout</strong> — AJAX cart, coupon codes, shipping zones, tax rules</li><li><strong>Payments</strong> — Cash on Delivery, Stripe, SSLCommerz integrations</li><li><strong>Customer Account</strong> — Order history, downloads tab, address management</li><li><strong>Sales Reports</strong> — Revenue by period (daily/weekly/monthly), top products, customer LTV, CSV export</li><li><strong>Shop Settings</strong> — Currency, inventory, email notifications, shipping, tax, coupon management</li></ul><h3 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h3><ul><li><strong>URL-aware Settings Tabs</strong> — Tab switches update the browser URL via <code>history.replaceState</code></li><li><strong>Sidebar Collapse</strong> — &quot;Collapse Menu&quot; button; icon-only mode persisted in <code>localStorage</code> with no flash on navigation</li><li><strong>FalconCMS Branding</strong> — FCM logo in admin top bar</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>HTTP Security Headers</strong> — <code>X-Content-Type-Options</code>, <code>X-Frame-Options</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code>, CSP, HSTS</li><li><strong>Rate Limiting</strong> — Login, forgot-password, comments, cart operations, file downloads</li><li><strong>CSRF Protection</strong> — All state-changing routes protected</li><li><strong>Input Validation</strong> — Cart quantities, file uploads, comment length, user enumeration prevention</li><li><strong>Secure Downloads</strong> — Token-based file delivery; tokens expire and have per-user download limits</li></ul><h3 id="developer-tools" tabindex="-1">Developer Tools <a class="header-anchor" href="#developer-tools" aria-label="Permalink to &quot;Developer Tools&quot;">​</a></h3><ul><li><strong>Artisan Commands</strong> — <code>lazy:expire-sales</code> (scheduled sale price cleanup)</li><li><strong>REST API</strong> — Configurable API key authentication</li><li><strong>Backup &amp; Snapshots</strong> — Database and file backup tools</li><li><strong>WordPress Import</strong> — Import posts from a WordPress XML export</li><li><strong>Analytics Dashboard</strong> — Basic traffic and content stats</li><li><strong>Maintenance Mode</strong> — Toggle from Customizer with custom message and countdown timer</li></ul>',78))])}const x=r(c,[["render",u]]);export{w as __pageData,x as default};
